// ── 6-Factor SCIENTIFIC scoring model ──
// Each sub-score is normalised to [0, 1]; weights sum to 100; composite × 100 displayed.
// Bias correction: adjusted = base + α × (PC − NR), α ∈ [0, 0.30]
const FACTORS = [
  { id: 'PC', label: 'People Choice',     defaultW: 30, formula: '1 − (closing ÷ maxClosing) × (1 + trend)', hint: 'Lower closing rank = higher demand. Trend correction from 2023→2025 closing-rank shift.' },
  { id: 'NR', label: 'NIRF Rank',         defaultW: 20, formula: '1 − (nirfRank ÷ 300)',                     hint: 'NIRF Engineering 2026. Lower rank ⇒ higher score. Unranked ⇒ 0.30 floor.' },
  { id: 'PL', label: 'Placement & CTC',   defaultW: 20, formula: 'avgCTC ÷ 25 LPA',                          hint: 'Outcome metric. ₹25 L = 1.0. Below your min CTC ⇒ −0.30 penalty.' },
  { id: 'BD', label: 'Branch Demand',     defaultW: 15, formula: 'branchPref ÷ 5',                           hint: 'CSE > ECE > Mech default. Edit per-branch chips below.' },
  { id: 'LS', label: 'Location/Exposure', defaultW: 10, formula: 'metroTier(city)',                          hint: 'Tier-1 metro = 1.00, Tier-2 = 0.70, Tier-3 = 0.45, remote = 0.25.' },
  { id: 'IL', label: 'Institute Legacy',  defaultW: 5,  formula: 'foundingHeritage(inst)',                   hint: 'Original RECs/heritage = 1.00; newer NITs = 0.30.' }
];

// Bias correction coefficient — boosts "hidden gems" where people-choice exceeds NIRF perception.
// Default 0.15. Range 0–0.30. adjusted = base + α × (PC − NR), clamped to [0, 1].
const ALPHA_DEFAULT = 0.15;
const ALPHA_MAX = 0.30;

// Branch demand defaults (1-5 scale, used in BD sub-score = pref/5)
const DEFAULT_BRANCH_PREF = {
  'CSE & IT': 5, 'CSE (AI/DS Specialization)': 5, 'AI & Data Science': 5,
  'CSE (Cyber Security)': 4, 'Electronics & Communication': 4, 'VLSI & Microelectronics': 4,
  'Electrical': 3, 'Mechanical & Production': 3, 'Aerospace': 3,
  'Mathematics': 3, 'Instrumentation': 3, 'Engineering Physics': 3,
  'Architecture & Planning': 3, 'Design': 3,
  'Civil': 2, 'Chemical': 2, 'Biotech & Biomedical': 2,
  'Metallurgy & Materials': 2, 'Energy': 2, 'Environmental': 2,
  'Mining': 1, 'Other': 2
};

// Metro tier sets — for Location/Exposure score
const METRO_T1 = new Set(['Delhi','New Delhi','Mumbai','Bengaluru','Bangalore','Chennai','Kolkata','Hyderabad']);
const METRO_T2 = new Set(['Pune','Ahmedabad','Coimbatore','Surat','Jaipur','Lucknow','Kochi','Visakhapatnam','Vizag','Chandigarh','Bhopal','Indore','Nagpur','Vadodara','Bhubaneswar','Gurugram','Noida','Greater Noida','Mangalore','Mangaluru','Goa','Panaji','Madgaon','Vasco','Kozhikode','Calicut','Trivandrum','Thiruvananthapuram']);
