function printPDF(scope) {
  if (mode === 'student') {
    showToast('PDF report is part of the expert workflow.', 'warn', 3500);
    return;
  }
  scope = scope || 'all';

  // Apply scope class on body so CSS @media print rules can hide irrelevant blocks
  document.body.classList.remove(
    'print-target-all','print-target-list1','print-target-list2','print-target-list3','print-target-list4','print-target-race'
  );
  document.body.classList.add('print-target-' + scope);

  // Force re-render so all four list bodies are populated
  // For per-list scopes, also activate that pane so it's visible during print
  if (scope === 'list4') {
    setActiveList('list4');
  } else if (scope === 'race') {
    // Race is in its own section — no list activation needed
    renderRace();
  } else {
    setActiveList(scope === 'all' ? 'list3' : scope);
    renderTable();
  }

  let header = $('#printHeader');
  if (!header) {
    header = document.createElement('div');
    header.id = 'printHeader';
    header.className = 'print-only print-header';
    document.body.insertBefore(header, document.body.firstChild);
  }
  const totalW = Object.values(weights).reduce((a,b) => a+b, 0);
  const defaultWStr = FACTORS.map(f => `${f.label}: <b>${f.defaultW}%</b>`).join(' &middot; ');
  const expertWStr = FACTORS.map(f => `${f.label}: <b>${weights[f.id]}%</b>`).join(' &middot; ');

  // Per-scope header titles
  const scopeTitles = {
    all:    { title: 'DASA Choice Filling Matrix &mdash; Full Report',          subtitle: 'All 4 lists &middot; comparison &middot; NIRF race' },
    list1:  { title: 'DASA Choice Filling &mdash; List 1 (Student Preference)', subtitle: 'Default weights with student inputs applied' },
    list2:  { title: 'DASA Choice Filling &mdash; List 2 (EduAakashaa Default)',subtitle: 'Standard 30/20/20/15/10/5 baseline, no student filters' },
    list3:  { title: 'DASA Choice Filling &mdash; List 3 (Expert-Tuned)',       subtitle: 'Live expert weights + α + comparison vs L1/L2' },
    list4:  { title: 'DASA Choice Filling &mdash; List 4 (Strategic Rounds)',   subtitle: '4-round manual choice list with allotment flags' },
    race:   { title: 'NIRF Positioning Race',                                   subtitle: 'Best reachable NIRF rank per course group' }
  };
  const sc = scopeTitles[scope] || scopeTitles.all;

  // Build a scope-aware "How to read" callout
  const howToReadByScope = {
    all:   `<b>How to read:</b> List 1 = student preference applied. List 2 = our default model. List 3 = your expert tuning with up/down arrows vs List 2. List 4 = manually-curated 4-round picks. Yellow-highlighted rows marked &#9312; &#9313; &#9314; show the program the student would actually be allotted in each list (first row whose closing rank covers their CRL).`,
    list1: `<b>List 1 isolation report.</b> Default 30/20/20/15/10/5 weights, with the student's branch chips, preferred zones and minimum CTC applied as filters. Yellow-highlighted row marked &#9312; shows the program the student would actually be allotted from this ordering.`,
    list2: `<b>List 2 isolation report.</b> Same default weights, but no student-specific filters &mdash; this is what our 6-factor model recommends out of the box for any student of this DASA route. Yellow-highlighted row marked &#9313; shows the expected allotment.`,
    list3: `<b>List 3 isolation report.</b> Live expert weights and &alpha; bias. Up/down arrows vs List 2. Yellow-highlighted row marked &#9314; shows the expected allotment after expert tuning.`,
    list4: `<b>List 4 isolation report.</b> Four sequential rounds of manual picks, each with its own conditions snapshot and allotment flag. Already-locked picks are excluded from later rounds.`,
    race:  `<b>NIRF Race report.</b> For the student's CRL, this shows the lowest NIRF rank reachable in each course group. The marker positions show where on the 1&ndash;300 NIRF scale the family lands per branch &mdash; useful for showing what's left on the table by being too narrow about course choice.`
  };

  // Compose meta — student profile is always relevant
  const profileMeta = `
    <div class="print-meta-grid">
      <div><b>Student CRL</b><br>${studentRank ? studentRank.toLocaleString('en-IN') : '&mdash;'}</div>
      <div><b>DASA category</b><br>${category}</div>
      <div><b>Preferred zones</b><br>${Array.from(prefZones).join(', ') || '&mdash;'}</div>
      <div><b>Min CTC</b><br>${minCTC ? '&#8377;' + minCTC + 'L' : '&mdash;'}</div>
    </div>
  `;

  // Weights summary — only relevant for list1/list2/list3 and 'all'
  const weightsBlock = (scope === 'race' || scope === 'list4') ? '' : `
    <div style="margin-top: 10px; padding: 8px 12px; background: #fafafa; border-radius: 6px; font-size: 10px; color: #333;">
      ${(scope === 'list3' || scope === 'all') ? `
      <div style="margin-bottom: 4px;"><b style="color: #071A44;">List 1 / List 2 (default weights, &alpha; = ${ALPHA_DEFAULT.toFixed(2)}):</b> ${defaultWStr}</div>
      <div style="border-top: 1px dashed #ccc; padding-top: 4px; margin-top: 4px;"><b style="color: #071A44;">List 3 (expert weights &Sigma; ${totalW}%, &alpha; = ${alphaBCF.toFixed(2)}):</b> ${expertWStr}</div>
      ` : `
      <div><b style="color: #071A44;">Default weights, &alpha; = ${ALPHA_DEFAULT.toFixed(2)}:</b> ${defaultWStr}</div>
      `}
    </div>
  `;

  // List 4 round summary block — only when scope is list4 or all
  let l4SummaryBlock = '';
  if (scope === 'list4' || scope === 'all') {
    const rows = STRAT_ROUNDS.map(rk => {
      const r = strategicRounds[rk];
      const rNum = rk.slice(1);
      let allotInfo = '<i>no allotment</i>';
      if (studentRank && r.choices.length > 0) {
        for (const pid of r.choices) {
          const p = programByProgId(pid);
          if (p && p.closing && studentRank <= p.closing) {
            allotInfo = `<b>${p.inst}</b> &middot; ${abbrevBranch(p.branchGroup)}`;
            break;
          }
        }
      }
      return `<tr style="border-bottom: 1px solid #eee;"><td style="padding: 4px 8px;"><b>R${rNum}</b></td><td style="padding: 4px 8px;">${r.choices.length} picks</td><td style="padding: 4px 8px;">${r.locked ? '<span style="color:#1F8B5C;">✓ locked</span>' : '<span style="color:#5A6278;">unlocked</span>'}</td><td style="padding: 4px 8px;">${allotInfo}</td></tr>`;
    }).join('');
    l4SummaryBlock = `
      <div style="margin-top: 10px; padding: 8px 12px; background: rgba(255,107,10,0.06); border-left: 3px solid #FF6B0A; border-radius: 4px; font-size: 10px; color: #333;">
        <b style="color: #071A44;">List 4 Rounds Summary:</b>
        <table style="width: 100%; margin-top: 6px; font-size: 10px; border-collapse: collapse;">
          <thead style="border-bottom: 1.5px solid #071A44;">
            <tr style="text-align: left;"><th style="padding: 4px 8px;">Round</th><th style="padding: 4px 8px;">Picks</th><th style="padding: 4px 8px;">Status</th><th style="padding: 4px 8px;">Expected allotment</th></tr>
          </thead>
          <tbody>${rows}</tbody>
        </table>
      </div>
    `;
  }

  header.innerHTML = `
    <div style="display:flex; align-items:center; gap:14px; margin-bottom: 10px;">
      <img src="${EDUAAKASHAA_LOGO}" alt="EduAakashaa" style="height: 52px; width: auto;">
      <div>
        <h1 style="font-size: 22px; color: #071A44; margin: 0; font-family: 'Fraunces', serif;">${sc.title}</h1>
        <div style="font-family: 'JetBrains Mono', monospace; font-size: 9.5px; color: #5A6278; text-transform: uppercase; letter-spacing: 0.18em; margin-top: 4px;">
          ${sc.subtitle} &middot; Generated ${new Date().toLocaleString()}
        </div>
      </div>
    </div>
    ${profileMeta}
    ${weightsBlock}
    ${l4SummaryBlock}
    <div style="margin-top: 8px; padding: 8px 12px; background: #FFF3E8; border-left: 3px solid #FF6B0A; border-radius: 4px; font-size: 10px; color: #333;">
      ${howToReadByScope[scope] || howToReadByScope.all}
    </div>
  `;

  // Inject print-only footer with logo + contact
  let footer = $('#printFooter');
  if (!footer) {
    footer = document.createElement('div');
    footer.id = 'printFooter';
    footer.className = 'print-only print-footer';
    document.body.appendChild(footer);
  }
  footer.innerHTML = `
    <div style="display:flex; align-items:center; gap:10px;">
      <img src="${EDUAAKASHAA_LOGO}" alt="EduAakashaa">
      <div>
        <div style="font-family:'Fraunces',serif; font-weight:700; font-size:13px; color:#071A44;">Edu<span style="color:#FF6B0A;">Aakashaa</span></div>
        <div style="font-family:'JetBrains Mono',monospace; font-size:8px; color:#5A6278; letter-spacing:0.16em; text-transform:uppercase;">Guiding students &middot; right future</div>
      </div>
    </div>
    <div class="pf-contact">
      <div><b>India:</b> +91 80157 22706</div>
      <div><b>Email:</b> info@eduaakashaa.com &nbsp;&middot;&nbsp; <b>Web:</b> www.eduaakashaa.in</div>
      <div style="margin-top:3px;">Coimbatore, Tamil Nadu &nbsp;&middot;&nbsp; Mon&ndash;Fri 9:00&ndash;22:00 &middot; Sat &amp; Sun 9:00&ndash;16:00</div>
    </div>
  `;

  // Ensure the DOM has fully painted before opening the print dialog.
  // Two requestAnimationFrames + a small buffer guarantees layout, style, and
  // paint phases have all completed for the just-rendered list pane.
  requestAnimationFrame(() => requestAnimationFrame(() => {
    setTimeout(() => {
      window.print();
      // Strip the scope class shortly after the print dialog closes so the page
      // returns to its normal interactive state.
      setTimeout(() => {
        document.body.classList.remove(
          'print-target-all','print-target-list1','print-target-list2','print-target-list3','print-target-list4','print-target-race','print-target-nri'
        );
      }, 400);
    }, 250);
  }));
}

// ──────────────────────────────────────────────────────────
//  MODE SWITCHING
// ──────────────────────────────────────────────────────────
function setMode(m) {
  mode = m;
  const isStudent = m === 'student';
  document.body.classList.toggle('is-student', isStudent);

  $('#modeTag').textContent = isStudent ? 'STUDENT PORTAL' : 'EXPERT PORTAL';
  $('#modeText').textContent = isStudent
    ? 'Quick preview only. Enter your CRL, branch and zone — we show your top matches. The full optimisation, three-list comparison, and downloadable report are part of the expert review.'
    : 'Full controls. Three-list optimiser (preference / default / expert-tuned), comparison panel, and CSV + PDF export.';
  $$('.mode-toggle button').forEach(b => b.classList.toggle('active', b.dataset.mode === m));

  if (isStudent) {
    renderStudentPreview();
  } else {
    // Re-render the matrix when returning to expert
    renderTable();
  }
}

// ──────────────────────────────────────────────────────────
//  STUDENT PREVIEW
//  Simple top-10 list. No weight controls, no presets, no exports.
// ──────────────────────────────────────────────────────────
function renderStudentPreview() {
  const tbody = $('#spTbody');
  const meta = $('#spTableMeta');
  if (!tbody) return;

  const rank = parseInt($('#spRank').value, 10) || null;
  const branch = $('#spBranch').value || '';
  const zone = $('#spZone').value || '';
  const cat = $('#spCategory').value || 'CIWG';

  if (!rank) {
    tbody.innerHTML = `<tr><td colspan="5" style="text-align:center; color: var(--muted); padding: 28px;">&mdash; preview will populate once you enter your CRL &mdash;</td></tr>`;
    meta.textContent = 'Enter your CRL to see top matches';
    return;
  }

  // Synthesize a temporary scoring run with student inputs
  const W = defaultWeights();
  const tempBranchPref = { ...DEFAULT_BRANCH_PREF };
  if (branch) tempBranchPref[branch] = 5; // boost selected branch

  // Compute scores using the student's CRL (override studentRank temporarily)
  const savedRank = studentRank;
  studentRank = rank;
  const scored = scoreCore({
    weights: W,
    alpha: ALPHA_DEFAULT,
    branchPrefMap: tempBranchPref,
    applyMinCTC: false,
    listKey: 'student-preview'
  });
  studentRank = savedRank;

  // Filter by category, optional branch, optional zone
  let visible = scored.filter(x => {
    if (x.p.category !== cat) return false;
    if (branch && x.p.branchGroup !== branch) return false;
    if (zone) {
      const z = (INST_META[x.p.inst] || {}).zone;
      if (z !== zone) return false;
    }
    return true;
  });
  // Re-rank within filter
  visible.forEach((x, i) => { x.filteredRank = i + 1; });

  meta.textContent = `Top matches for CRL ${rank.toLocaleString('en-IN')}${branch ? ' · ' + branch : ''}${zone ? ' · ' + zone : ''} · ${visible.length} programs`;

  if (visible.length === 0) {
    tbody.innerHTML = `<tr><td colspan="5" style="text-align:center; color: var(--muted); padding: 28px;">No matches for this combination. Try widening your zone or branch.</td></tr>`;
    return;
  }

  // Show top 10 only
  const topMatches = visible.slice(0, 10);
  tbody.innerHTML = topMatches.map(x => {
    const m = INST_META[x.p.inst] || {};
    return `
      <tr>
        <td><b>${x.filteredRank}</b></td>
        <td>
          <span class="sp-inst">${x.p.inst}</span>
          <span class="sp-branch">${abbrevBranch(x.p.branchGroup)} &middot; ${x.p.prog}</span>
        </td>
        <td>${x.p.nirfRank ?? '&mdash;'}</td>
        <td>${fmtNum(x.p.closing)}</td>
        <td>${x.fit ? `<span class="fit-pill ${x.fit}">${x.fit}</span>` : '&mdash;'}</td>
      </tr>
    `;
  }).join('');
}

