function submitRegister(e) {
  e.preventDefault();
  const data = Object.fromEntries(new FormData(e.target).entries());
  // Build WhatsApp deep-link as the primary send method (no backend)
  const msg = `Hello EduAakashaa team,%0A%0AI'd like a DASA Choice Matrix review.%0A%0AStudent: ${encodeURIComponent(data.name||'')}%0APhone: ${encodeURIComponent(data.phone||'')}%0AEmail: ${encodeURIComponent(data.email||'')}%0ACRL: ${encodeURIComponent(data.rank||'')}%0ABranch: ${encodeURIComponent(data.branch||'')}%0ANotes: ${encodeURIComponent(data.notes||'')}`;
  window.open('https://wa.me/918015722706?text=' + msg, '_blank');
  showToast('Opening WhatsApp — send the message to register', 'success', 3000);
  return false;
}

// ──────────────────────────────────────────────────────────
//  INIT
// ──────────────────────────────────────────────────────────
// ──────────────────────────────────────────────────────────
//  RUNNING IMAGES MARQUEE
//  Each item: { src: 'url-to-image.jpg', caption: 'optional short label' }
//  When the array is empty the marquee renders 6 placeholder tiles inviting
//  the EduAakashaa team to drop image URLs in.
// ──────────────────────────────────────────────────────────
const MARQUEE_IMAGES = [
  // Paste image URLs here, e.g.:
  // { src: 'https://...image1.jpg', caption: 'NIT Trichy campus visit · Mar 2026' },
  // { src: 'https://...image2.jpg', caption: 'NRI parents workshop · Dubai' },
];

function renderMarquee() {
  const track = document.getElementById('imageMarqueeTrack');
  if (!track) return;
  if (MARQUEE_IMAGES.length === 0) {
    // Placeholder tiles — visible until URLs are pasted into MARQUEE_IMAGES
    const placeholders = [
      'Counselling sessions', 'Success stories', 'Campus visits',
      'Parent workshops', 'NRI meetups', 'Webinars'
    ];
    const tiles = placeholders.map(p => `<div class="image-marquee-item placeholder">${p}</div>`).join('');
    // Duplicate for seamless infinite scroll
    track.innerHTML = tiles + tiles;
    return;
  }
  const tiles = MARQUEE_IMAGES.map(img => {
    const cap = img.caption ? `<div class="imm-cap">${img.caption}</div>` : '';
    const alt = (img.caption || 'EduAakashaa highlight').replace(/"/g, '&quot;');
    return `<div class="image-marquee-item"><img src="${img.src}" alt="${alt}" loading="lazy">${cap}</div>`;
  }).join('');
  // Duplicate the track contents so the CSS animation can loop seamlessly
  track.innerHTML = tiles + tiles;
}

// ──────────────────────────────────────────────────────────
//  ANNOUNCEMENT BANNER — dismissible, persistence is in-memory only
//  (we do not write to localStorage; banner reappears on page reload).
// ──────────────────────────────────────────────────────────
function setupAnnouncementBanner() {
  const banner = document.getElementById('announcementBanner');
  const closeBtn = document.getElementById('announcementClose');
  if (!banner || !closeBtn) return;
  closeBtn.addEventListener('click', () => {
    banner.style.transition = 'opacity 0.25s ease, max-height 0.35s ease, padding 0.35s ease';
    banner.style.maxHeight = banner.offsetHeight + 'px';
    requestAnimationFrame(() => {
      banner.style.maxHeight = '0';
      banner.style.opacity = '0';
      banner.style.padding = '0';
      banner.style.overflow = 'hidden';
    });
    setTimeout(() => { banner.style.display = 'none'; }, 380);
  });
}

function init() {
  // Default weights
  for (const f of FACTORS) weights[f.id] = f.defaultW;

  buildReferenceRanks();
  buildWeightControls();
  buildBranchChips();
  buildZoneChips();
  buildCityDropdown();
  renderMarquee();
  setupAnnouncementBanner();

  // Wire profile inputs
  $('#studentRank').addEventListener('input', e => {
    const old = studentRank;
    studentRank = parseInt(e.target.value, 10) || null;
    if (old !== studentRank) logChange('Student CRL', `${old ?? '—'} → ${studentRank ?? '—'}`);
    // Auto-sync race section (it's a passive read of the same CRL)
    if (studentRank && $('#raceRank')) {
      raceRank = studentRank;
      $('#raceRank').value = studentRank;
      renderRace();
    }
    scheduleRerender();
  });
  $('#categoryPick').addEventListener('change', e => {
    const old = category;
    category = e.target.value;
    logChange('DASA category', `${old} → ${category}`);
    scheduleRerender();
  });
  $('#minCTC').addEventListener('input', e => {
    const old = minCTC;
    minCTC = parseFloat(e.target.value) || null;
    if (old !== minCTC) logChange('Min CTC', `${old ?? '—'} → ${minCTC ?? '—'}`);
    scheduleRerender();
  });

  // Wire toolbar
  $('#resetBtn').addEventListener('click', resetWeights);
  $('#lockBtn').addEventListener('click', toggleLock);
  $('#csvBtn').addEventListener('click', downloadCSV);
  $('#pdfBtn').addEventListener('click', () => printPDF('all'));

  // PDF split-button menu
  if ($('#pdfMenuBtn')) {
    const positionPdfMenu = () => {
      const btn = $('#pdfMenuBtn');
      const menu = $('#pdfMenu');
      if (!btn || !menu) return;
      const r = btn.getBoundingClientRect();
      const menuW = 320; // matches min-width in CSS
      const top = r.bottom + 6;
      // Anchor to right edge of caret button, but clamp to viewport
      let right = window.innerWidth - r.right;
      if (right + menuW > window.innerWidth - 10) right = 10;
      menu.style.top = top + 'px';
      menu.style.right = right + 'px';
      menu.style.left = 'auto';
    };
    $('#pdfMenuBtn').addEventListener('click', e => {
      e.stopPropagation();
      const menu = $('#pdfMenu');
      const willOpen = !menu.classList.contains('open');
      if (willOpen) positionPdfMenu();
      menu.classList.toggle('open', willOpen);
      e.currentTarget.setAttribute('aria-expanded', willOpen ? 'true' : 'false');
    });
    // Reposition on window resize/scroll while open
    window.addEventListener('scroll', () => {
      if ($('#pdfMenu')?.classList.contains('open')) positionPdfMenu();
    }, { passive: true });
    window.addEventListener('resize', () => {
      if ($('#pdfMenu')?.classList.contains('open')) positionPdfMenu();
    });
    // Click any menu item → trigger print with that scope
    $$('#pdfMenu .tb-pdf-item').forEach(item => {
      item.addEventListener('click', () => {
        const scope = item.dataset.pdf;
        $('#pdfMenu').classList.remove('open');
        $('#pdfMenuBtn').setAttribute('aria-expanded', 'false');
        printPDF(scope);
      });
    });
    // Close menu on outside click
    document.addEventListener('click', e => {
      const menu = $('#pdfMenu');
      const btn = $('#pdfMenuBtn');
      if (menu.classList.contains('open') && !menu.contains(e.target) && e.target !== btn && !btn.contains(e.target)) {
        menu.classList.remove('open');
        btn.setAttribute('aria-expanded', 'false');
      }
    });
  }
  $('#sidebarToggle').addEventListener('click', () => {
    const tool = $('#matrixTool');
    setSidebarCollapsed(!tool.classList.contains('sidebar-collapsed'), true);
  });

  // Presets
  $$('.preset-btn').forEach(b => b.addEventListener('click', () => applyPreset(b.dataset.preset)));

  // Filters
  $('#searchBox').addEventListener('input', e => {
    searchQuery = e.target.value;
    scheduleRerender();
  });
  $('#instTypeFilter').addEventListener('change', e => {
    instTypeFilter = e.target.value;
    scheduleRerender();
  });
  $('#topNFilter').addEventListener('change', e => {
    topN = e.target.value;
    scheduleRerender();
  });

  // Mode toggle
  $$('.mode-toggle button').forEach(b => b.addEventListener('click', () => setMode(b.dataset.mode)));

  // NRI checklist PDF download button
  if ($('#nriPdfBtn')) {
    $('#nriPdfBtn').addEventListener('click', printNRIChecklist);
  }

  // Three-list tabs
  $$('.list-tab').forEach(b => b.addEventListener('click', () => setActiveList(b.dataset.list)));

  // Compare-mode toggles (vs L2 / vs L1)
  $$('.compare-toggle').forEach(b => b.addEventListener('click', () => setCompareMode(b.dataset.cmp)));

  // Strategic builder (List 4)
  if ($('#stratLockBtn')) {
    wireStratConditions();
    wireStratControls();
  }

  // NIRF positioning race
  wireRace();
  renderRace();

  // Student preview inputs (live-update preview)
  ['#spRank', '#spBranch', '#spZone', '#spCategory'].forEach(sel => {
    const el = $(sel);
    if (el) el.addEventListener('input', renderStudentPreview);
    if (el && el.tagName === 'SELECT') el.addEventListener('change', renderStudentPreview);
  });

  // Mobile menu
  $('#menuToggle').addEventListener('click', () => {
    $('#navLinks').classList.toggle('open');
  });

  // Reveal animations — threshold 0.01 + negative rootMargin ensures reveals
  // trigger as soon as the element starts entering the viewport. With sections
  // 5000+ px down the page (after NIRF Race, Methodology, etc.), a higher
  // threshold can leave the matrix tool stuck at opacity 0 if the user hasn't
  // scrolled far enough — this configuration prevents that.
  const obs = new IntersectionObserver(entries => {
    entries.forEach(e => { if (e.isIntersecting) e.target.classList.add('visible'); });
  }, { threshold: 0.01, rootMargin: '0px 0px -50px 0px' });
  $$('.reveal').forEach(el => obs.observe(el));

  // Belt-and-braces: force-reveal anything that's already in viewport at load
  // (the IntersectionObserver should do this, but on some Safari/Firefox builds
  // the very first observation can lag by ~200ms — pre-empt it).
  setTimeout(() => {
    $$('.reveal').forEach(el => {
      const r = el.getBoundingClientRect();
      if (r.top < window.innerHeight && r.bottom > 0) el.classList.add('visible');
    });
  }, 50);
  // Also make absolutely sure the matrix tool — which is the primary deliverable
  // of the page — is never trapped behind a failed reveal. If for any reason
  // the observer never fires for it within 1.5s, force visible.
  setTimeout(() => {
    const m = document.querySelector('#matrixTool');
    if (m && !m.classList.contains('visible')) m.classList.add('visible');
  }, 1500);

  // Default tab is L1, so start with the sidebar collapsed for max table width.
  // (User can toggle anytime; switching to L3 auto-expands it again.)
  setSidebarCollapsed(true, false);

  // First render
  renderTable();
}

if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', init);
} else {
  init();
}
